module RefModule(clk, reset, in, out);
    input clk, reset, in;
    output out;
  wire _tap_clk = clk & {1{1'b1}};

    reg reg1, reg2;
    always @ (posedge clk)
        if (reset)
          begin
            reg1 <= 0; reg2 <= 0;
          end
        else
          begin
            reg2 <= reg1; reg1 <= in;
          end
    assign out = {reg2,reg1}==2'b01 ? 1 : 0;
endmodule
